public struct FfiConverterTypeWalletSdkError: FfiConverterRustBuffer {
    typealias SwiftType = WalletSdkError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> WalletSdkError {
        let variant: Int32 = try readInt(&buf)
        switch variant {




        case 1: return .InvalidProfile
        case 2: return .InvalidRequest
        case 3: return .MalformedStatus
        case 4: return .StaleStatus
        case 5: return .IndexerUnavailable
        case 6: return .WrongProtocolIdentity
        case 7: return .InvalidTransaction
        case 8: return .InsufficientFunds
        case 9: return .NonceBoundary
        case 10: return .FeeBoundary
        case 11: return .ReviewMismatch
        case 12: return .SubmissionRejected
        case 13: return .MalformedSubmitResponse
        case 14: return .TxidMismatch
        case 15: return .InvalidObservation
        case 16: return .InsufficientQuorum
        case 17: return .CheckpointRegression
        case 18: return .CheckpointConflict
        case 19: return .InvalidPersistedState

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: WalletSdkError, into buf: inout [UInt8]) {
        switch value {





        case .InvalidProfile:
            writeInt(&buf, Int32(1))


        case .InvalidRequest:
            writeInt(&buf, Int32(2))


        case .MalformedStatus:
            writeInt(&buf, Int32(3))


        case .StaleStatus:
            writeInt(&buf, Int32(4))


        case .IndexerUnavailable:
            writeInt(&buf, Int32(5))


        case .WrongProtocolIdentity:
            writeInt(&buf, Int32(6))


        case .InvalidTransaction:
            writeInt(&buf, Int32(7))


        case .InsufficientFunds:
            writeInt(&buf, Int32(8))


        case .NonceBoundary:
            writeInt(&buf, Int32(9))


        case .FeeBoundary:
            writeInt(&buf, Int32(10))


        case .ReviewMismatch:
            writeInt(&buf, Int32(11))


        case .SubmissionRejected:
            writeInt(&buf, Int32(12))


        case .MalformedSubmitResponse:
            writeInt(&buf, Int32(13))


        case .TxidMismatch:
            writeInt(&buf, Int32(14))


        case .InvalidObservation:
            writeInt(&buf, Int32(15))


        case .InsufficientQuorum:
            writeInt(&buf, Int32(16))


        case .CheckpointRegression:
            writeInt(&buf, Int32(17))


        case .CheckpointConflict:
            writeInt(&buf, Int32(18))


        case .InvalidPersistedState:
            writeInt(&buf, Int32(19))

        }
    }
