private enum InitializationResult {
    case ok
    case contractVersionMismatch
    case apiChecksumMismatch
}
// Use a global variable to perform the versioning checks. Swift ensures that
// the code inside is only computed once.
private let initializationResult: InitializationResult = {
    // Get the bindings contract version from our ComponentInterface
    let bindings_contract_version = 30
    // Get the scaffolding contract version by calling the into the dylib
    let scaffolding_contract_version = ffi_noos_wallet_sdk_uniffi_contract_version()
    if bindings_contract_version != scaffolding_contract_version {
        return InitializationResult.contractVersionMismatch
    }
    if (uniffi_noos_wallet_sdk_checksum_method_mobilelightnode_export_state() != 1004) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_noos_wallet_sdk_checksum_method_mobilelightnode_observe_finalized() != 17780) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_noos_wallet_sdk_checksum_method_mobilelightnode_snapshot() != 36040) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_noos_wallet_sdk_checksum_method_mobilewalletcore_derive_authority() != 26800) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_noos_wallet_sdk_checksum_method_mobilewalletcore_review_transfer() != 35068) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_noos_wallet_sdk_checksum_method_mobilewalletcore_sign_reviewed_transfer() != 18019) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_noos_wallet_sdk_checksum_method_mobilewalletcore_validate_submission_response() != 19250) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_noos_wallet_sdk_checksum_method_mobilewalletcore_verify_status() != 17141) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_noos_wallet_sdk_checksum_constructor_mobilelightnode_new() != 62684) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_noos_wallet_sdk_checksum_constructor_mobilewalletcore_new() != 57686) {
        return InitializationResult.apiChecksumMismatch
    }

    return InitializationResult.ok
}()

// Make the ensure init function public so that other modules which have external type references to
// our types can call it.
public func uniffiEnsureNoosWalletSdkInitialized() {
    switch initializationResult {
    case .ok:
        break
    case .contractVersionMismatch:
        fatalError("UniFFI contract version mismatch: try cleaning and rebuilding your project")
    case .apiChecksumMismatch:
        fatalError("UniFFI API checksum mismatch: try cleaning and rebuilding your project")
    }
}

